function TrainersList({ trainers, selectedTrainerId, onSelectTrainer }) {
  return (
    <div className="card trainer-list">
      <h3>Trainers</h3>
      {trainers.map((trainer) => (
        <button
          key={trainer.id}
          className={trainer.id === selectedTrainerId ? 'active' : ''}
          onClick={() => onSelectTrainer(trainer.id)}
        >
          {trainer.name}
        </button>
      ))}
    </div>
  );
}

export default TrainersList;
